# Create customer segments using RFM-like approach
# R = Recency (tenure), F = Frequency (activity), M = Monetary (spend)

# Define segments based on multiple criteria
def assign_segment(row):
    spend = row['monthly_spend_clean']
    active = row['is_active']
    plan = row['plan_tier']
    tenure = row['tenure_days']

    # High-value segments
    if spend >= 100:
        return 'VIP Champions'
    elif spend >= 30 and active:
        return 'High-Value Active'
    elif spend >= 30 and not active:
        return 'High-Value At-Risk'

    # Medium-value segments
    elif spend >= 10 and spend < 30 and active:
        return 'Promising Engaged'
    elif spend >= 10 and spend < 30 and not active:
        return 'Medium At-Risk'

    # Low-value segments
    elif spend > 0 and spend < 10 and active and tenure < 365:
        return 'New Explorers'
    elif spend > 0 and spend < 10 and active and tenure >= 365:
        return 'Loyal Low-Spend'
    elif spend > 0 and spend < 10 and not active:
        return 'Low-Value Churned'

    # Zero spend segments
    elif spend == 0 and active and tenure < 90:
        return 'Fresh Signups'
    elif spend == 0 and active and tenure >= 90:
        return 'Free Riders'
    elif spend == 0 and not active:
        return 'Inactive Free'

    else:
        return 'Other'

df['segment'] = df.apply(assign_segment, axis=1)

print("Customer Segments:")
print(df['segment'].value_counts())
print("\nSegment distribution:")
segment_summary = df.groupby('segment').agg({
    'user_id': 'count',
    'monthly_spend_clean': ['mean', 'sum'],
    'is_active': 'mean',
    'tenure_days': 'mean'
}).round(2)
segment_summary.columns = ['Count', 'Avg Spend', 'Total Spend', 'Active %', 'Avg Tenure (days)']
print(segment_summary.sort_values('Total Spend', ascending=False))
